1	// claim-office.ts
2	
3	export type Customer = {
4	  yearsWithMHPCO: number;
5	  previousContracts?: number;
6	};
7	
8	export type Item = unknown;
9	
10	export type QuoteInput = {
11	  customer: Customer;
12	  items: Item[];
13	};
14	
15	export function quote(_input: QuoteInput): number {
16	  return 5;
17	}
18

1	// claim-office.spec.ts
2	import { describe, it, expect } from "vitest";
3	import { quote } from "./claim-office.js";
4	
5	describe("MHPCO Claim Office", () => {
6	  // ===== Quote: empty and processing fee =====
7	  it("empty item list yields premium of 5 G (processing fee only)", () => {
8	    expect(quote({ customer: { yearsWithMHPCO: 0, previousContracts: 0 }, items: [] })).toBe(5);
9	  });
10	
11	  // ===== Quote: single item base premiums (no modifiers, follow-up contract to neutralize first-insurance) =====
12	  // Use a long-standing customer's follow-up contract OR show base via integration.
13	  // We start with the simplest: single-item premiums combining base + first-insurance for a newcomer with no history.
14	  it.todo("newcomer single sword (steel, enchantment 0, not cursed) yields premium 115 G (100 base + 10 first-insurance + 5 fee)");
15	  it.todo("newcomer single amulet yields premium 71 G (60 base + 6 first-insurance + 5 fee)");
16	  it.todo("newcomer single staff yields premium 93 G (80 base + 8 first-insurance + 5 fee)");
17	  it.todo("newcomer single potion yields premium 49 G (40 base + 4 first-insurance + 5 fee)");
18	  it.todo("newcomer single rune yields premium 33 G (25 base + 3 first-insurance + 5 fee, rounded up)");
19	
20	  // ===== Quote: component blocks =====
21	  it.todo("2 runes yield base premium 50 G (no block applies)");
22	  it.todo("3 runes yield base premium 60 G (block of 3 alike applies)");
23	  it.todo("4 runes yield base premium 100 G (block requires exactly 3)");
24	  it.todo("7 runes yield base premium 175 G (no block)");
25	  it.todo("2 runes + 1 moonstone yield base premium 75 G (different types, no block)");
26	  it.todo("3 runes + 3 moonstones yield base premium 120 G (two separate blocks)");
27	
28	  // ===== Quote: item-specific modifiers =====
29	  it.todo("cursed sword adds 50% surcharge on item base (cursed sword alone: 100 + 50 = 150 base)");
30	  it.todo("highly enchanted sword (enchantment 5) adds 30% surcharge on item base");
31	  it.todo("sword with enchantment 4 has no high-enchantment surcharge");
32	  it.todo("cursed sword with enchantment 5 stacks both surcharges on item base");
33	
34	  // ===== Quote: modifier scope on multi-item policies =====
35	  it.todo("policy with cursed sword + plain amulet: cursed surcharge applies only to cursed item base (newcomer total 231 G)");
36	
37	  // ===== Quote: policy-wide modifiers =====
38	  it.todo("long-standing customer (exactly 2 years) receives 20% loyalty discount on policy base");
39	  it.todo("first insurance (newcomer, no prior contracts) adds 10% surcharge on policy base");
40	  it.todo("follow-up contract gives 15% discount on policy base");
41	
42	  // ===== Quote: rounding in MHPCO's favor =====
43	  it.todo("premium calculation that yields 197.5 G rounds up to 198 G");
44	  it.todo("intermediate amounts kept as fractions; only final premium is rounded");
45	
46	  // ===== Quote: integration examples from spec =====
47	  it.todo("newcomer with cursed sword (steel, enchantment 3) yields premium 165 G");
48	  it.todo("long-standing (3 yrs) customer's second quote with cursed sword (enchantment 7) yields premium 160 G");
49	
50	  // ===== Claim: basic deductible =====
51	  it.todo("regular sword (steel, enchantment 3), damage 500 G yields payout 400 G (full minus 100 deductible)");
52	  it.todo("rune (insurance value 250 G), damage 200 G yields payout 100 G (full minus deductible, no special clauses)");
53	
54	  // ===== Claim: special clauses =====
55	  it.todo("steel sword enchantment 9, damage 1000 G yields payout 400 G (50% then deductible)");
56	  it.todo("dragon-material sword enchantment 5, damage 800 G yields payout 700 G (full minus deductible)");
57	  it.todo("dragon-material sword enchantment 9, damage 1000 G yields payout 400 G (50% then deductible — both clauses apply)");
58	  it.todo("dragon-material sword exactly enchantment 8, damage 1000 G yields payout 400 G (50% then deductible)");
59	
60	  // ===== Claim: deductible per damage event (multi-item incident) =====
61	  it.todo("dragon attack damages sword (500 G) and amulet (300 G): payout 600 G (deductible per item)");
62	
63	  // ===== Claim: rounding =====
64	  it.todo("payout calculation that yields 350.5 G rounds down to 350 G");
65	
66	  // ===== Claim: insurance sum and cap =====
67	  it.todo("policy of sword + amulet: insurance sum 1600 G, cap 3200 G");
68	  it.todo("policy of sword + 3 runes (a block): insurance sum 1750 G (block discount affects premium only)");
69	  it.todo("cursed sword: cap 2000 G based on unmodified insurance value (premium modifiers do not raise cap)");
70	
71	  // ===== Claim: cap exhaustion across successive claims =====
72	  it.todo("sword (cap 2000 G), first claim 1500 G yields payout 1400 G, remainingCap 600 G");
73	  it.todo("sword (cap 2000 G), after first 1500 G claim, second 1500 G claim yields payout 600 G, remainingCap 0 G");
74	
75	  // ===== Claim: multiple items of same type =====
76	  it.todo("policy covers two swords: insurance sum 2000 G, cap 4000 G");
77	  it.todo("dragon attack damages both insured swords: each entry treated separately with own deductible");
78	
79	  // ===== CLI / scenario integration =====
80	  it.todo("scenario with quote then claim returns results array of length 2 with {premium} and {payout, remainingCap}");
81	
82	  // ===== Error cases =====
83	  it.todo("quote with unknown item type (e.g. broomstick) causes CLI to exit non-zero with stderr error");
84	  it.todo("claim referencing damage to an item not in the policy causes CLI to exit non-zero with stderr error");
85	  it.todo("claim with damages array containing more entries of a type than insured causes CLI to exit non-zero");
86	  it.todo("claim with negative damage amount causes CLI to exit non-zero with stderr error");
87	});
